def validate_id_token(id_token):
    """Validate ID token signature and claims"""
    try:
        # Get JWKS
        jwks = get_jwks()
        
        # Decode header to get kid
        unverified_header = jwt.get_unverified_header(id_token)
        kid = unverified_header.get('kid')
        
        if not kid:
            app.logger.error("No kid in token header")
            return None
        
        # Find matching key
        rsa_key = None
        for key in jwks.get('keys', []):
            if key.get('kid') == kid:
                rsa_key = jwt.algorithms.RSAAlgorithm.from_jwk(key)
                break
        
        if not rsa_key:
            app.logger.error("No matching key found in JWKS")
            return None
        
        # Verify and decode token
        payload = jwt.decode(
            id_token,
            rsa_key,
            algorithms=['RS256'],
            audience=OIDC_CLIENT_ID,
            issuer=OIDC_ISSUER,
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_iat': True,
                'verify_aud': True,
                'verify_iss': True,
                'require': ['exp', 'iat', 'aud', 'iss', 'sub']
            }
        )
        
        return payload
        
    except jwt.ExpiredSignatureError:
        app.logger.error("Token has expired")
        return None
    except jwt.InvalidAudienceError:
        app.logger.error("Invalid audience")
        return None
    except jwt.InvalidIssuerError:
        app.logger.error("Invalid issuer")
        return None
    except Exception as e:
        app.logger.error(f"Token validation failed: {str(e)}")
        return None


