@app.route('/callback')
def callback():
    """Handle OIDC callback"""
    # Validate state parameter to prevent CSRF
    state = request.args.get('state')
    stored_state = session.pop('oauth_state', None)
    
    if not state or not stored_state or state != stored_state:
        app.logger.error("Invalid state parameter")
        abort(400, "Invalid state parameter")
    
    # Check for error response
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        app.logger.error(f"OIDC error: {error} - {error_description}")
        abort(400, "Authentication failed")
    
    # Get authorization code
    code = request.args.get('code')
    if not code:
        app.logger.error("No authorization code received")
        abort(400, "No authorization code received")
    
    # Exchange code for tokens
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': OIDC_CLIENT_ID,
        'client_secret': OIDC_CLIENT_SECRET
    }
    
    try:
        token_response = requests.post(
            OIDC_TOKEN_ENDPOINT,
            data=token_data,
            timeout=10,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except Exception as e:
        app.logger.error(f"Token exchange failed: {str(e)}")
        abort(500, "Token exchange failed")
    
    # Validate ID token
