    # Validate nonce
    stored_nonce = session.pop('oauth_nonce', None)
    token_nonce = payload.get('nonce')
    
    if not stored_nonce or not token_nonce or stored_nonce != token_nonce:
        app.logger.error("Nonce validation failed")
        abort(400, "Invalid nonce")
    
    # Store user information in session
    session.permanent = True
    session['user_id'] = payload.get('sub')
    session['user_email'] = payload.get('email')
    session['user_name'] = payload.get('name')
    
    # Do not store tokens in session or logs
    
